// Global stats
struct TestStats {
    uint32_t passed;
    uint32_t failed;
    uint32_t total;
};
static TestStats g_stats = {0, 0, 0};

// Curved Spacetime Wave Simulator
// Box_g (Phi) = 0
struct SpacetimeSim {
    float phi[WAVE_GRID_SIZE];
    float phi_prev[WAVE_GRID_SIZE];
    float phi_next[WAVE_GRID_SIZE];
    // Spacetime metric components: g^00 (time) and g^11 (space)
    float g00[WAVE_GRID_SIZE];
    float g11[WAVE_GRID_SIZE];
    float source_amplitude;
    uint32_t step;
};

void init_spacetime_sim(SpacetimeSim *sim) {
    std::memset(sim->phi, 0, sizeof(sim->phi));
    std::memset(sim->phi_prev, 0, sizeof(sim->phi_prev));
    std::memset(sim->phi_next, 0, sizeof(sim->phi_next));
    
    // Initialize metric components to flat space (Minkowski space: g^00 = -1, g^11 = 1)
    // Here we use absolute values for the numerical updates
    for (int i = 0; i < WAVE_GRID_SIZE; i++) {
        sim->g00[i] = 1.0f;
        sim->g11[i] = 1.0f;
    }
    sim->source_amplitude = 0.0f;
    sim->step = 0;
}

// Update the spacetime metric based on external wave amplitudes (the other 4 equations)
void modulate_metric(SpacetimeSim *sim, float wave1, float wave2, float wave3, float wave4) {
    float coupling = 0.15f * (wave1 + wave2 + wave3 + wave4);
    for (int i = 0; i < WAVE_GRID_SIZE; i++) {
        // Curve the spacetime metric near the center of the grid representing a high energy density event
        float dist_from_center = static_cast<float>(std::abs(i - (WAVE_GRID_SIZE / 2)));
        float spatial_profile = std::exp(-(dist_from_center * dist_from_center) / 50.0f);
        
        sim->g00[i] = 1.0f + coupling * spatial_profile;
        sim->g11[i] = 1.0f / (1.0f + coupling * spatial_profile); // length contraction (Schwarzschild-like)
    }
}

void step_spacetime_sim(SpacetimeSim *sim, float dt) {
    if (dt <= 0.0f) {
        std::cout << "  [WARNING] Telemetry query step bypassed: dt must be positive (Received: " << dt << ")\n";
        return;
    }

    float r2 = WAVE_COURANT * WAVE_COURANT;
    sim->source_amplitude = std::sin(0.2f * sim->step * dt);

    // Wave equation in curved spacetime:
    // d/dt ( sqrt(-g) g^00 d(phi)/dt ) + d/dx ( sqrt(-g) g^11 d(phi)/dx ) = 0
    // Using standard finite difference discretization
    for (int i = 1; i < WAVE_GRID_SIZE - 1; i++) {
        // Approximate metric determinant: det(g) = -g00 * g11 = -1 in flat space
        float det_g_prev = sim->g00[i-1] * sim->g11[i-1];
        float det_g_curr = sim->g00[i] * sim->g11[i];
        float det_g_next = sim->g00[i+1] * sim->g11[i+1];
        
        float sqrt_g_prev = std::sqrt(std::abs(det_g_prev));
        float sqrt_g_curr = std::sqrt(std::abs(det_g_curr));
        float sqrt_g_next = std::sqrt(std::abs(det_g_next));

        // Spatial derivative part: d/dx ( sqrt(-g) g^11 d(phi)/dx )
        float term_x_next = sqrt_g_next * sim->g11[i+1] * (sim->phi[i+1] - sim->phi[i]);
        float term_x_prev = sqrt_g_prev * sim->g11[i-1] * (sim->phi[i] - sim->phi[i-1]);
        float spatial_div = term_x_next - term_x_prev;

        // Time update including metric multipliers
        float factor = r2 / (sqrt_g_curr * sim->g00[i]);
        sim->phi_next[i] = 2.0f * sim->phi[i] - sim->phi_prev[i] + factor * spatial_div;

        if (sim->phi_next[i] != sim->phi_next[i] || sim->phi_next[i] > 1e9f || sim->phi_next[i] < -1e9f) {
            std::cout << "  [CRITICAL] Numerical singularity detected in spacetime wave. Auto-healing to zero...\n";
            init_spacetime_sim(sim);
            return;
        }
    }

    // Node 0 driven by metric boundary condition
    sim->phi_next[0] = sim->source_amplitude;
    sim->phi_next[WAVE_GRID_SIZE - 1] = 0.0f;

    std::memcpy(sim->phi_prev, sim->phi, sizeof(sim->phi));
    std::memcpy(sim->phi, sim->phi_next, sizeof(sim->phi));

    sim->step++;
}

void print_wave_profile(const SpacetimeSim *sim) {
    const int height = 11;
    const int mid_y = height / 2;
    char display[11][WAVE_GRID_SIZE + 1];

    for (int i = 0; i < height; i++) {
        for (int j = 0; j < WAVE_GRID_SIZE; j++) {
            display[i][j] = (i == mid_y) ? '-' : ' ';
        }
        display[i][WAVE_GRID_SIZE] = '\0';
    }

    for (int i = 0; i < WAVE_GRID_SIZE; i++) {
        float val = sim->phi[i];
        if (val > 1.5f) val = 1.5f;
        if (val < -1.5f) val = -1.5f;

        int y = mid_y - (int)std::round(val * (float)mid_y / 1.5f);
        if (y < 0) y = 0;
        if (y >= height) y = height - 1;

        display[y][i] = (y == mid_y) ? 'o' : '*';
    }

    std::cout << "  [Step " << std::setw(3) << std::setfill('0') << sim->step
              << " | Geodesic Amplitude: " << std::showpos << std::fixed << std::setprecision(4)
              << sim->source_amplitude << "]\n";
    std::cout << "  +----------------------------------------+\n";
    for (int i = 0; i < height; i++) {
        std::cout << "  |" << display[i] << "|\n";
    }
    std::cout << "  +----------------------------------------+\n";
}

